class Solution:
    def minimumCost(self, m, n, horizontalCut, verticalCut):
        cuts = [(-c, 0) for c in horizontalCut] + [(-c, 1) for c in verticalCut]
        cuts.sort()
        hCount, vCount, total = 1, 1, 0
        for negc, typ in cuts:
            c = -negc
            if typ == 0:
                total += c * vCount
                hCount += 1
            else:
                total += c * hCount
                vCount += 1
        return total

