var minimumCost = function(m, n, horizontalCut, verticalCut) {
    const cuts = [];
    for (const c of horizontalCut) cuts.push([c, 0]);
    for (const c of verticalCut) cuts.push([c, 1]);
    cuts.sort((a, b) => b[0] - a[0]);
    let hCount = 1, vCount = 1, total = 0;
    for (const [c, typ] of cuts) {
        if (typ === 0) {
            total += c * vCount;
            hCount += 1;
        } else {
            total += c * hCount;
            vCount += 1;
        }
    }
    return total;
};
